from flask import Flask, request, jsonify
import subprocess
import json
import os
from functools import wraps

app = Flask(__name__)

def load_tokens():
    with open('/root/webhooks/tokens.json') as f:
        return json.load(f)

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.args.get('auth_token')
        if not token:
            return jsonify({"error": "Missing auth_token"}), 401
        tokens = load_tokens()
        if token not in tokens:
            return jsonify({"error": "Invalid token"}), 403
        return f(*args, **kwargs)
    return decorated

@app.route('/flash-peter-office-lights')
@token_required
def flash_lights():
    try:
        cmd = 'ssh -i /root/.ssh/pi_key peter@100.x.x.x "/home/peter/flash_lights.sh"'
        result = subprocess.run(cmd, shell=True, timeout=15, capture_output=True, text=True)
        if result.returncode != 0:
            return jsonify({"error": "Script execution failed", "details": result.stderr}), 500
        return jsonify({
            "status": "success",
            "user": load_tokens()[request.args.get('auth_token')]["name"]
        })
    except subprocess.TimeoutExpired:
        return jsonify({"error": "Command timed out"}), 504
    except Exception as e:
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

